import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/fundamentals`},{default:a(()=>[...l[2]||=[n(`Fundamentals`,-1)]]),_:1}),l[5]||=n(` › Chapter 1 `,-1)]),l[6]||=i(`<h1>Chapter 1: Introduction</h1><p class="chapter-desc">What software architecture really is, the three universal laws, and the eight core expectations of a software architect.</p><div class="stats-bar"><span class="stat-badge">4 Architecture Dimensions</span><span class="stat-badge">3 Laws</span><span class="stat-badge">8 Architect Expectations</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<div class="toc"><h2>Table of Contents</h2><ol><li><a href="#s1-1">Defining Software Architecture</a></li><li><a href="#s1-2">The Laws of Software Architecture</a></li><li><a href="#s1-3">Expectations of an Architect</a></li><li><a href="#s1-4">Roadmap of the Book</a></li><li><a href="#takeaways">Key Takeaways</a></li></ol></div><h2 class="section-title" id="s1-1">Defining Software Architecture</h2><div class="content-section"><p>Software architecture is not a single thing — it has four dimensions that together define it. Architects analyze these dimensions to understand and design systems:</p><table class="comparison-table"><thead><tr><th>Dimension</th><th>Question it answers</th><th>Description</th></tr></thead><tbody><tr><td><strong>Architecture Style</strong></td><td>How is the system structured?</td><td>The named topology: microservices, layered, event-driven, etc. The starting point for implementation.</td></tr><tr><td><strong>Architecture Characteristics (&quot;-ilities&quot;)</strong></td><td>What must the system be capable of?</td><td>Scalability, availability, performance, security, maintainability, etc. Capabilities independent of the problem domain.</td></tr><tr><td><strong>Logical Components</strong></td><td>What is the system&#39;s behavior?</td><td>The domains, entities, and workflows of the application. How functionality is structured and divided.</td></tr><tr><td><strong>Architecture Decisions</strong></td><td>Why was it built this way?</td><td>Rules and constraints for how the system must be constructed. For example: &quot;Only the Business layer may access the database.&quot;</td></tr></tbody></table><div class="info-box analogy-box"><p><strong>Analogy:</strong> Think of building a house. The <em>architecture style</em> is the overall plan (ranch, colonial, contemporary). The <em>characteristics</em> are requirements like earthquake resistance or fire safety. The <em>logical components</em> are the rooms and their relationships. The <em>decisions</em> are the building codes and constraints (&quot;load-bearing walls must be here&quot;).</p></div><div class="info-box note-box"><p><strong>Context matters:</strong> All architectures are products of their environment. In 2002, building microservices would have required 50+ commercial OS licenses, 30+ application server licenses, and 50+ database licenses — impossibly expensive. Only the arrival of open source software and the DevOps revolution made it feasible today.</p></div></div><h2 class="section-title" id="s1-2">The Laws of Software Architecture</h2><div class="content-section"><p>The authors identified three universal laws that apply across all software architectures:</p><div class="pattern-summary"><h4>First Law: Everything in software architecture is a trade-off.</h4><div class="ps-row"><span class="ps-label">Corollary 1:</span> <span>If you think you&#39;ve discovered something that isn&#39;t a trade-off, more likely you just haven&#39;t identified the trade-off yet.</span></div><div class="ps-row"><span class="ps-label">Corollary 2:</span> <span>You can&#39;t just do trade-off analysis once. Every situation requires re-evaluation because context changes.</span></div></div><div class="pattern-summary"><h4>Second Law: Why is more important than how.</h4><div class="ps-row"><span class="ps-label">Implication:</span> <span>Understanding how an architecture works is relatively easy. Understanding why certain decisions were made — what trade-offs were considered, what context existed — is far harder and more valuable.</span></div><div class="ps-row"><span class="ps-label">Practical use:</span> <span>Document architecture decisions with their rationale (Architecture Decision Records, ADRs). Future architects will thank you.</span></div></div><div class="pattern-summary"><h4>Third Law: Most architecture decisions aren&#39;t binary but exist on a spectrum.</h4><div class="ps-row"><span class="ps-label">Implication:</span> <span>Architecture is rarely &quot;use X or don&#39;t use X.&quot; It&#39;s about how much, when, and in what context. For example, choosing choreography vs orchestration depends on the specific workflow — not a one-size-fits-all rule.</span></div></div><div class="info-box key-point-box"><p><strong>The helicopter analogy:</strong> Flying a helicopter requires coordinating controls for both hands and both feet — changing one affects all others. Software architecture characteristics are similarly synergistic. Improving security usually degrades performance. Improving scalability often sacrifices simplicity. Architects learn to balance these interlocking forces.</p></div></div><h2 class="section-title" id="s1-3">Expectations of a Software Architect</h2><div class="content-section"><p>Regardless of title or company, eight core expectations define what it means to be a software architect:</p><table class="comparison-table"><thead><tr><th>#</th><th>Expectation</th><th>Key insight</th></tr></thead><tbody><tr><td>1</td><td><strong>Make Architecture Decisions</strong></td><td>Guide technology choices rather than specify them. An architect should say &quot;use a reactive frontend framework&quot; (not &quot;use React specifically&quot;) unless there&#39;s an architectural reason for a specific choice.</td></tr><tr><td>2</td><td><strong>Continually Analyze the Architecture</strong></td><td>Assess architecture vitality — how well does a 3-year-old design hold up to today&#39;s requirements? Identify structural decay caused by accumulated design decisions.</td></tr><tr><td>3</td><td><strong>Keep Current with Latest Trends</strong></td><td>Architects&#39; decisions are long-lasting and hard to change. Staying current (cloud, AI, new frameworks) helps make decisions that remain relevant. The 20-minute rule (Chapter 2) helps.</td></tr><tr><td>4</td><td><strong>Ensure Compliance with Decisions</strong></td><td>Architecture decisions are useless if ignored. The architect must verify that teams follow the defined constraints (fitness functions, Chapter 6, help automate this).</td></tr><tr><td>5</td><td><strong>Understand Diverse Technologies</strong></td><td>Focus on <strong>technical breadth</strong> over technical depth. Better to know the pros and cons of 10 caching solutions than to be an expert in only one.</td></tr><tr><td>6</td><td><strong>Know the Business Domain</strong></td><td>Cannot design an effective banking system without understanding financial terms. The best architects can communicate with C-level executives in business language.</td></tr><tr><td>7</td><td><strong>Possess Interpersonal Skills</strong></td><td>&quot;No matter what they tell you, it&#39;s always a people problem.&quot; — Gerald Weinberg. Leadership and facilitation are at least half the job.</td></tr><tr><td>8</td><td><strong>Understand and Navigate Politics</strong></td><td>Almost every architecture decision will be challenged. The architect must negotiate and justify decisions to developers, product owners, project managers, and executives.</td></tr></tbody></table><div class="info-box analogy-box"><p><strong>Technical Breadth vs Depth:</strong> Imagine an iceberg. Everything above the water is what you know deeply (depth). Technical breadth includes everything you know about but not in detail — the submerged mass of the iceberg. A developer needs a sharp, deep spike of expertise. An architect needs a wide, broad base that lets them understand the landscape and evaluate trade-offs.</p></div></div><h2 class="section-title" id="s1-4">Roadmap of the Book</h2><div class="content-section"><table class="comparison-table"><thead><tr><th>Part</th><th>Chapters</th><th>Focus</th></tr></thead><tbody><tr><td><strong>Part I: Foundations</strong></td><td>1–8</td><td>Architectural characteristics, logical component design, modularity — the analytical tools an architect uses before choosing a style.</td></tr><tr><td><strong>Part II: Architecture Styles</strong></td><td>9–17</td><td>A catalog of named architectural topologies: layered, modular monolith, pipeline, microkernel, service-based, event-driven, space-based, microservices.</td></tr><tr><td><strong>Part III: Techniques &amp; Soft Skills</strong></td><td>18–27</td><td>Architecture decisions, risk analysis, diagramming, team topologies, negotiation, presentations, and career paths.</td></tr></tbody></table></div><div class="takeaways" id="takeaways"><h3>Key Takeaways — Chapter 1</h3><ul><li>Software architecture has <strong>four dimensions</strong>: architecture style, characteristics (&quot;-ilities&quot;), logical components, and decisions.</li><li><strong>First Law:</strong> Everything is a trade-off. <strong>Second Law:</strong> Why &gt; How. <strong>Third Law:</strong> Decisions are on a spectrum, not binary.</li><li>Architecture decisions are long-lasting and hard to change — that&#39;s what distinguishes them from design decisions.</li><li>Architects need <strong>technical breadth</strong> (wide knowledge landscape) more than depth (narrow specialization).</li><li>The role is at least 50% interpersonal skills — leadership, facilitation, negotiation. These are often harder to acquire than technical skills.</li><li>The context of any architecture matters enormously — architectures that are impossible in one era become table stakes in the next (microservices = unthinkable in 2002, standard in 2025).</li></ul></div>`,10),e(`div`,p,[r(m,{to:`/sa/fundamentals`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Book Index`,-1)]]),_:1}),r(m,{to:`/sa/fundamentals/ch2`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 2 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};